import pytest

from calc import divide, percent


# --- divide ---------------------------------------------------------------


def test_divide_basic():
    assert divide(10, 2) == 5


def test_divide_negative_numbers():
    assert divide(-10, 2) == -5
    assert divide(10, -2) == -5
    assert divide(-10, -2) == 5


def test_divide_returns_float_for_inexact_division():
    assert divide(1, 3) == pytest.approx(0.3333333333333333)


def test_divide_zero_dividend():
    assert divide(0, 5) == 0


def test_divide_by_zero_raises():
    with pytest.raises(ValueError, match="cannot divide by zero"):
        divide(10, 0)


# --- percent ----------------------------------------------------------------


def test_percent_basic():
    assert percent(50, 200) == 25


def test_percent_full_whole():
    assert percent(200, 200) == 100


def test_percent_zero_part():
    assert percent(0, 200) == 0


def test_percent_part_greater_than_whole():
    assert percent(400, 200) == 200


def test_percent_negative_values():
    assert percent(-50, 200) == -25


def test_percent_by_zero_whole_raises():
    with pytest.raises(ValueError, match="cannot divide by zero"):
        percent(50, 0)

import pytest

from metrics import mean


def test_mean_basic():
    assert mean([1, 2, 3, 4]) == 2.5


def test_mean_single_value():
    assert mean([7]) == 7


def test_mean_negative_numbers():
    assert mean([-1, -2, -3]) == -2


def test_mean_mixed_sign_numbers():
    assert mean([-10, 10]) == 0


def test_mean_floats():
    assert mean([1.5, 2.5, 3.0]) == pytest.approx(2.3333333333333335)


def test_mean_of_zeros():
    assert mean([0, 0, 0]) == 0


def test_mean_empty_list_raises():
    with pytest.raises(ValueError, match="no values"):
        mean([])

